/** STUB FILE **/

/** Call-by-value, Call-by-name, and Call-by-need Jam interpreter */

import java.io.IOException;
import java.io.Reader;

/** Interpreter Classes */

/** A class that implements call-by-value, call-by-name, and call-by-need interpretation of Jam programs. */
class Interpreter {
  
  /** program for this interpeter, initialized in constructors. */
  AST prog;
  
  /** Constructor for a program given in a file. Not used in Assignment 2*/
  public Interpreter(String fileName) throws IOException { 
    Parser p = new Parser(fileName);
    prog = p.parse();
  }
  
  /** Constructor for a program already embedded in a Parser object. */
  public Interpreter(Parser p) { 
    prog = p.parse();
  }  
  
  /** Constructor for a program embedded in a Reader. Not used in Assignment 2. */
  public Interpreter(Reader reader) { 
    Parser p = new Parser(reader);
    prog = p.parse();
  }
  
  /** Parses and CBV interprets the input embeded in parser */
  public JamVal callByValue() { return prog.accept(valueEvalVisitor); }
  
  /** Parses and CBNm interprets the input embeded in parser */
  public JamVal callByName() { return prog.accept(nameEvalVisitor); }
  
  /** Parses and CBNd interprets the input embeded in parser */
  public JamVal callByNeed() { return prog.accept(needEvalVisitor); }
   
  /** A class representing an unevaluated expresssion (together with the corresponding evaluator). */
  private static class ConcreteSuspension implements Suspension {
    private AST exp;
    private EvalVisitor ev;  
    
    ConcreteSuspension(AST a, EvalVisitor e) { exp = a; ev = e; }
    
    AST exp() { return exp; }
    EvalVisitor ev() { return ev; }
    void putEv(EvalVisitor e) { ev = e; }
    
    /** Evaluates this suspension. Only method of Suspension interface. */
    public JamVal eval() { 
      // System.err.println("eval() called on the susp with AST = " + exp);
      return exp.accept(ev);  } 
    
    public String toString() { return "<" + exp + ", " + ev + ">"; }
  }
  
  /** Class representing a binding in CBV evaluation. */
  private static class ValueBinding extends Binding {
    ValueBinding(Variable v, JamVal jv) { super(v, jv); }
    public JamVal value() { return value; }
    public void setBinding(Suspension s) { /* Not used in CBV */ }
    public String toString() { return "[" + var + ", " + value + "]"; }
  }
  
  /** Class representing a binding in CBName evaluation. The inherited value field is ignored. */
  private static class NameBinding extends Binding {
    protected Suspension susp;
    NameBinding(Variable v, Suspension s) {
      super(v, null);
      susp = s;
    }
    public JamVal value() { return susp.eval(); }
    public void setBinding(Suspension s) { susp = s; }
    public String toString() { return "[" + var + ", " + susp + "]"; }
  }
  
  /** Class representing a binding in CBNeed evaluation.  The inherited value field is used to hold the value
    * first computed by need-driven evaluation. */
  private static class NeedBinding extends NameBinding {
    NeedBinding(Variable v, Suspension s) { super(v, s); }
    public JamVal value() {
      if (value == null) {
        value = susp.eval();
      }
      return value;
    }
    public String toString() { return "[" + var + ", " + value + ", " + susp + "]"; }
  }
  
  /** Visitor class implementing a lookup method on environments.
    * @return value() for variable var for both lazy and eager environments. */
  private static class LookupVisitor implements PureListVisitor<Binding, JamVal> {

    Variable var;   // the lexer guarantees that there is only one Variable for a given name

    LookupVisitor(Variable v) { var = v; }

    /* Visitor methods. */
    public JamVal forEmpty(Empty<Binding> e) {
      throw new EvalException("Variable `" + var.name() + "' is unbound");
    }
    public JamVal forCons(Cons<Binding> c) {
      Binding binding = c.first();
      if (binding.var() == var) {
        return binding.value();
      } else {
        return c.rest().accept(this);
      }
    }
  }
 
  /** The interface supporting various evaluation policies (CBV, CBNm, CBNd) for map applications and let constructions. 
    * The EvalVisitor parameter appears in each method because the variable is bound to the value of the AST which is
    * determined using the specified EvalVisitor.  Note: all of the differences among CBV, CBNm, and CBNd evaluation can 
    * be encapulated in different implementations of the Binding interface.  Perhaps this interface should be called
    * BindingPolicy.  Since this interface is not part of the Interpreter API required by Assign2Test.java, you are free
    * to rename it if you choose.
    */
  private interface EvalPolicy {
    /** Constructs the appropriate binding object for this, binding var to ast in the evaluator ev */
    Binding newBinding(Variable var, AST ast, EvalVisitor ev);
  }
  
  /** An ASTVisitor class for evaluating ASTs where the evaluation policy for function applications and other
    * binding operations such as let are determined by an embedded EvalPolicy. */
  private static class EvalVisitor implements ASTVisitor<JamVal> {
    
    /* The code in this class assumes that:
     * * OpTokens are unique; 
     * * Variable objects are unique: v1.name.equals(v.name) => v1 == v2; and
     * * The only objects used as boolean values are BoolConstant.TRUE and BoolConstant.FALSE.
     * Hence,  == can be used to compare Variable objects, OpTokens, and BoolConstants. */
    
    private PureList<Binding> env;  // the embdedded environment
    private EvalPolicy evalPolicy;  // the embedded EvalPolicy
    
    /** Constructor for recursive calls. */
    private EvalVisitor(PureList<Binding> e, EvalPolicy ep) { 
      env = e; 
      evalPolicy = ep; 
    }
    
    /** Top level constructor. */
    public EvalVisitor(EvalPolicy ep) { this(new Empty<Binding>(), ep); }
    
    /** Factory method that constructs a new visitor with environment e and same evalPolicy as this.  It is used
      * for recursive invocations of this evaluator.  Essential in some contexts because it has access to evalPolicy. */
    public EvalVisitor newVisitor(PureList<Binding> e) {
      return new EvalVisitor(e, evalPolicy);
    }

    /** Factory method that constructs a Binding of var to ast corresponding to this.evalPolicy */
    public Binding newBinding(Variable var, AST ast) {
      return evalPolicy.newBinding(var, ast, this);
    }
    
    /** Getter for env field */
    public PureList<Binding> env() { return env; }
    
    /* ASTVisitor methods */
    public JamVal forBoolConstant(BoolConstant b) { return b; }
    public JamVal forIntConstant(IntConstant i) { return i; }
    public JamVal forEmptyConstant(EmptyConstant n) { return JamEmpty.ONLY; }
    public JamVal forVariable(Variable v) {
      LookupVisitor lv = new LookupVisitor(v);
      return env.accept(lv);
    }

    public JamVal forPrimFun(PrimFun f) { return f; }
    
    public JamVal forUnOpApp(UnOpApp u) {
      JamVal arg = u.arg().accept(this);
      StandardUnOpVisitor suv = new StandardUnOpVisitor(arg);
      return u.rator().accept(suv);
    }
    
    public JamVal forBinOpApp(BinOpApp b) {
      StandardBinOpVisitor sbv = new StandardBinOpVisitor(b.arg1(), b.arg2(), this);
      return b.rator().accept(sbv);
    }
    
    public JamVal forApp(App a) {
      JamFun fun = (JamFun) a.rator().accept(this);
      StandardFunVisitor sfv = new StandardFunVisitor(a.args(), this);
      return fun.accept(sfv);
    }
    
    public JamVal forMap(Map m) {
      return new JamClosure(m, env);
    }
    
    public JamVal forIf(If i) {
      JamVal test = i.test().accept(this);
      if (!(test instanceof BoolConstant)) {
        throw new EvalException("if test " + test + " is not a boolean");
      }
      BoolConstant testBool = (BoolConstant) test;
      if (testBool.value()) {
        return i.conseq().accept(this);
      } else {
        return i.alt().accept(this);
      }
    }
    
    /* let (non-recursive) semantics */
    public JamVal forLet(Let l) {
      Def[] defs = l.defs();
      Variable[] vars = new Variable[defs.length];
      AST[] args = new AST[defs.length];
      for (int i = 0; i < defs.length; i++) {
        vars[i] = defs[i].lhs();
        args[i] = defs[i].rhs();
      }
      Map mapAst = new Map(vars, l.body());
      App appAst = new App(mapAst, args);
      return appAst.accept(this);
    }
  }
  
  /** Top-level EvalVisitors implementing CBV, CBNm, and CBNd evaluation. */
  private static EvalVisitor valueEvalVisitor = new EvalVisitor(CallByValue.ONLY);
  private static EvalVisitor nameEvalVisitor = new EvalVisitor(CallByName.ONLY);
  private static EvalVisitor needEvalVisitor = new EvalVisitor(CallByNeed.ONLY);
  
  /** JamFunVisitor class that evaluates the application of a JamFun (the host) to the argument expressions given in
    * AST[] args unsing the given evalVisitor, which interprets ASTs. The evalVisitor is used to evaluate args and to 
    * generate the new visitor for evaluating the map body embedded of the JamFun if it is a JamClosure. */
  private static class StandardFunVisitor implements JamFunVisitor<JamVal> {
    
    /** Unevaluated arguments */
    AST[] args;
    
    /** Evaluation visitor */
    EvalVisitor evalVisitor;
    
    StandardFunVisitor(AST[] asts, EvalVisitor ev) {
      args = asts;
      evalVisitor = ev;
    }
    
    /** Evaluate the arguments of a PrimFun application. */
    private JamVal[] evalArgs() {
      JamVal[] values = new JamVal[args.length];
      for (int i = 0; i < args.length; i++) {
        values[i] = args[i].accept(evalVisitor);
      }
      return values;
    }

    /* Visitor methods. */
    public JamVal forJamClosure(JamClosure closure) {
      Map code = closure.code();
      Variable[] params = code.vars();
      if (params.length != args.length) {
        throw new EvalException("Closure " + code + " expects " + params.length +
                               " arguments but was given " + args.length);
      }
      PureList<Binding> closureEnv = closure.env();
      PureList<Binding> newEnv = closureEnv;
      // Evaluate arguments in the current evaluation environment (evalVisitor's environment)
      // Then create bindings for parameters
      for (int i = 0; i < params.length; i++) {
        Binding binding = evalVisitor.newBinding(params[i], args[i]);
        newEnv = newEnv.cons(binding);
      }
      // Evaluate body with the new environment (closure env + all parameter bindings)
      EvalVisitor bodyVisitor = evalVisitor.newVisitor(newEnv);
      return code.body().accept(bodyVisitor);
    }

    public JamVal forPrimFun(PrimFun primFun) {
      JamVal[] values = evalArgs();
      StandardPrimFunVisitor spfv = new StandardPrimFunVisitor(values);
      return primFun.accept(spfv);
    }
  }
  
  private static class CallByValue implements EvalPolicy {

    public static final EvalPolicy ONLY = new CallByValue();
    private CallByValue() { }

    /** Constructs binding of var to value of arg in ev */
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      JamVal val = arg.accept(ev);
      return new ValueBinding(var, val);
    }
  }
    
  private static class CallByName implements EvalPolicy {
    public static final EvalPolicy ONLY = new CallByName();
    private CallByName() {}

    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      Suspension susp = new ConcreteSuspension(arg, ev);
      return new NameBinding(var, susp);
    }
  }
  
  private static class CallByNeed implements EvalPolicy {
    public static final EvalPolicy ONLY = new CallByNeed();
    private CallByNeed() {}

    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      Suspension susp = new ConcreteSuspension(arg, ev);
      return new NeedBinding(var, susp);
    }
  }
  
  /* Only works for eager unary operators; need to add a newUnOpVisitor method to EvalPolicy if lazy unary operator is
   * added to Jam*/
  private static class StandardUnOpVisitor implements UnOpVisitor<JamVal> {
    private final JamVal val;
    StandardUnOpVisitor(JamVal jv) { val = jv; }
    
    /** Returns val provided it is an IntConstant; throw EvalException otherwise. */
    private IntConstant checkInteger(String op) {
      if (!(val instanceof IntConstant)) {
        throw new EvalException("Unary operator " + op + " applied to non-integer " + val);
      }
      return (IntConstant) val;
    }

    /** Returns val provided it is an BoolConstant; throw EvalException otherwise. */
    private BoolConstant checkBoolean(String op) {
      if (!(val instanceof BoolConstant)) {
        throw new EvalException("Unary operator " + op + " applied to non-boolean " + val);
      }
      return (BoolConstant) val;
    }

    public JamVal forUnOpPlus() {
      IntConstant i = checkInteger("+");
      return new IntConstant(i.value());
    }

    public JamVal forUnOpMinus() {
      IntConstant i = checkInteger("-");
      return new IntConstant(-i.value());
    }

    public JamVal forOpTilde() {
      BoolConstant b = checkBoolean("~");
      return b.not();
    }
    
    // public JamVal forOpBang() { return ... ; }  // Supports addition of ref cells to Jam in Assignment 4
    // public JamVal forOpRef() { return ... ; }   // Supports addition of ref cells to Jam in Assignment 4
  }
  
  private static class StandardBinOpVisitor implements BinOpVisitor<JamVal> { 
    private AST arg1, arg2;
    private EvalVisitor evalVisitor;
    
    StandardBinOpVisitor(AST a1, AST a2, EvalVisitor ev) { arg1 = a1; arg2 = a2; evalVisitor = ev; }
    
    /** Evaluate the specified argument AST and confirm that it is an IntConstant. */
    private IntConstant evalIntegerArg(AST arg, String op) {
      JamVal val = arg.accept(evalVisitor);
      if (!(val instanceof IntConstant)) {
        throw new EvalException("Binary operator " + op + " applied to non-integer " + val);
      }
      return (IntConstant) val;
    }

    /** Evaluate the specified argument AST and confirm that it is a BoolConstant. */
    private BoolConstant evalBooleanArg(AST arg, String op) {
      JamVal val = arg.accept(evalVisitor);
      if (!(val instanceof BoolConstant)) {
        throw new EvalException("Binary operator " + op + " applied to non-boolean " + val);
      }
      return (BoolConstant) val;
    }
    
    public JamVal forBinOpPlus() {
      IntConstant i1 = evalIntegerArg(arg1, "+");
      IntConstant i2 = evalIntegerArg(arg2, "+");
      return new IntConstant(i1.value() + i2.value());
    }

    public JamVal forBinOpMinus() {
      IntConstant i1 = evalIntegerArg(arg1, "-");
      IntConstant i2 = evalIntegerArg(arg2, "-");
      return new IntConstant(i1.value() - i2.value());
    }

    public JamVal forOpTimes() {
      IntConstant i1 = evalIntegerArg(arg1, "*");
      IntConstant i2 = evalIntegerArg(arg2, "*");
      return new IntConstant(i1.value() * i2.value());
    }

    public JamVal forOpDivide() {
      IntConstant i1 = evalIntegerArg(arg1, "/");
      IntConstant i2 = evalIntegerArg(arg2, "/");
      if (i2.value() == 0) {
        throw new EvalException("Division by zero");
      }
      return new IntConstant(i1.value() / i2.value());
    }
    
    public JamVal forOpEquals() {
      JamVal v1 = arg1.accept(evalVisitor);
      JamVal v2 = arg2.accept(evalVisitor);
      return BoolConstant.toBoolConstant(v1.equals(v2));
    }

    public JamVal forOpNotEquals() {
      JamVal v1 = arg1.accept(evalVisitor);
      JamVal v2 = arg2.accept(evalVisitor);
      return BoolConstant.toBoolConstant(!v1.equals(v2));
    }

    public JamVal forOpLessThan() {
      IntConstant i1 = evalIntegerArg(arg1, "<");
      IntConstant i2 = evalIntegerArg(arg2, "<");
      return BoolConstant.toBoolConstant(i1.value() < i2.value());
    }

    public JamVal forOpGreaterThan() {
      IntConstant i1 = evalIntegerArg(arg1, ">");
      IntConstant i2 = evalIntegerArg(arg2, ">");
      return BoolConstant.toBoolConstant(i1.value() > i2.value());
    }

    public JamVal forOpLessThanEquals() {
      IntConstant i1 = evalIntegerArg(arg1, "<=");
      IntConstant i2 = evalIntegerArg(arg2, "<=");
      return BoolConstant.toBoolConstant(i1.value() <= i2.value());
    }

    public JamVal forOpGreaterThanEquals() {
      IntConstant i1 = evalIntegerArg(arg1, ">=");
      IntConstant i2 = evalIntegerArg(arg2, ">=");
      return BoolConstant.toBoolConstant(i1.value() >= i2.value());
    }
    
    public JamVal forOpAnd() {
      JamVal v1 = arg1.accept(evalVisitor);
      if (!(v1 instanceof BoolConstant)) {
        throw new EvalException("Binary operator & applied to non-boolean " + v1);
      }
      BoolConstant b1 = (BoolConstant) v1;
      if (!b1.value()) {
        return BoolConstant.FALSE;
      }
      JamVal v2 = arg2.accept(evalVisitor);
      if (!(v2 instanceof BoolConstant)) {
        throw new EvalException("Binary operator & applied to non-boolean " + v2);
      }
      BoolConstant b2 = (BoolConstant) v2;
      return BoolConstant.toBoolConstant(b2.value());
    }

    public JamVal forOpOr() {
      JamVal v1 = arg1.accept(evalVisitor);
      if (!(v1 instanceof BoolConstant)) {
        throw new EvalException("Binary operator | applied to non-boolean " + v1);
      }
      BoolConstant b1 = (BoolConstant) v1;
      if (b1.value()) {
        return BoolConstant.TRUE;
      }
      JamVal v2 = arg2.accept(evalVisitor);
      if (!(v2 instanceof BoolConstant)) {
        throw new EvalException("Binary operator | applied to non-boolean " + v2);
      }
      BoolConstant b2 = (BoolConstant) v2;
      return BoolConstant.toBoolConstant(b2.value());
    }
    
    // public JamVal forOpGets(OpGets op) { return ... ; }  // Supports addition of ref cells to Jam in Assignment 4
  }
    
  /** Visitor that implements each primitive function.  Only supports strict functions. */
  private static class StandardPrimFunVisitor implements PrimFunVisitor<JamVal> {
    
    JamVal[] vals;  // evaluated arguments for PrimFun App
    
    StandardPrimFunVisitor(JamVal[] vls) { vals = vls; }
    
    private JamVal primFunError(String fn) {
      throw new EvalException("Primitive function `" + fn + "' applied to " + vals.length + " arguments");
    }
    
    /** Confirms that vals[0] (first evaluated argument in application of fun) is a JamCons. Assumes that any
      * such function is unary. */
    private JamCons confirmJamCons(String funName) {
      if (vals.length != 1) {
        throw new EvalException("Primitive function `" + funName + "' expects 1 argument but was given " + vals.length);
      }
      if (!(vals[0] instanceof JamCons)) {
        throw new EvalException("Primitive function `" + funName + "' applied to non-list " + vals[0]);
      }
      return (JamCons) vals[0];
    }
    
    public JamVal forFunctionPPrim() {
      if (vals.length != 1) {
        return BoolConstant.FALSE;
      }
      return BoolConstant.toBoolConstant(vals[0] instanceof JamFun);
    }

    public JamVal forNumberPPrim() {
      if (vals.length != 1) {
        return BoolConstant.FALSE;
      }
      return BoolConstant.toBoolConstant(vals[0] instanceof IntConstant);
    }

    public JamVal forListPPrim() {
      if (vals.length != 1) {
        return BoolConstant.FALSE;
      }
      return BoolConstant.toBoolConstant(vals[0] instanceof JamList);
    }

    public JamVal forConsPPrim() {
      if (vals.length != 1) {
        return BoolConstant.FALSE;
      }
      return BoolConstant.toBoolConstant(vals[0] instanceof JamCons);
    }

    public JamVal forEmptyPPrim() {
      if (vals.length != 1) {
        return BoolConstant.FALSE;
      }
      return BoolConstant.toBoolConstant(vals[0] instanceof JamEmpty);
    }
    public JamVal forConsPrim() {
      if (vals.length != 2) {
        throw new EvalException("Primitive function `cons' expects 2 arguments but was given " + vals.length);
      }
      JamVal arg2 = vals[1];
      if (!(arg2 instanceof JamList)) {
        throw new EvalException("Primitive function `cons' applied to non-list " + arg2);
      }
      JamList list = (JamList) arg2;
      return list.cons(vals[0]);
    }

    public JamVal forArityPrim() {
      if (vals.length != 1) {
        throw new EvalException("Primitive function `arity' expects 1 argument but was given " + vals.length);
      }
      if (!(vals[0] instanceof JamFun)) {
        throw new EvalException("Primitive function `arity' applied to non-function " + vals[0]);
      }
      JamFun fun = (JamFun) vals[0];
      if (fun instanceof JamClosure) {
        JamClosure closure = (JamClosure) fun;
        return new IntConstant(closure.code().vars().length);
      } else if (fun instanceof PrimFun) {
        PrimFun primFun = (PrimFun) fun;
        String name = primFun.name();
        // Most primitive functions are unary
        if (name.equals("function?") || name.equals("number?") || name.equals("list?") ||
            name.equals("cons?") || name.equals("empty?") || name.equals("arity") ||
            name.equals("first") || name.equals("rest")) {
          return new IntConstant(1);
        } else if (name.equals("cons")) {
          return new IntConstant(2);
        } else {
          throw new EvalException("Unknown primitive function `" + name + "'");
        }
      } else {
        throw new EvalException("Primitive function `arity' applied to unknown function " + vals[0]);
      }
    }

    public JamVal forFirstPrim() {
      if (vals.length != 1) {
        throw new EvalException("Primitive function `first' expects 1 argument but was given " + vals.length);
      }
      if (!(vals[0] instanceof JamCons)) {
        throw new EvalException("Primitive function `first' applied to non-cons list " + vals[0]);
      }
      JamCons cons = (JamCons) vals[0];
      return cons.first();
    }

    public JamVal forRestPrim() {
      if (vals.length != 1) {
        throw new EvalException("Primitive function `rest' expects 1 argument but was given " + vals.length);
      }
      if (!(vals[0] instanceof JamCons)) {
        throw new EvalException("Primitive function `rest' applied to non-cons list " + vals[0]);
      }
      JamCons cons = (JamCons) vals[0];
      return cons.rest();
    }
    
  }
}
 
class EvalException extends RuntimeException {
  EvalException(String msg) { super(msg); }
}

import junit.framework.TestCase;
import java.io.StringReader;

/**
 * Comprehensive unit tests for the Jam interpreter implementation.
 * Tests cover all three evaluation strategies: call-by-value, call-by-name, and call-by-need.
 */
public class InterpreterAgentTest extends TestCase {

  public InterpreterAgentTest(String name) {
    super(name);
  }

  // ============ Helper Methods ============

  private void valueCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("by-value " + name, answer, interp.callByValue().toString());
  }

  private void nameCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("by-name " + name, answer, interp.callByName().toString());
  }

  private void needCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("by-need " + name, answer, interp.callByNeed().toString());
  }

  private void allCheck(String name, String answer, String program) {
    valueCheck(name, answer, program);
    nameCheck(name, answer, program);
    needCheck(name, answer, program);
  }

  private void valueThrowsCheck(String name, String program) {
    try {
      Interpreter interp = new Interpreter(new StringReader(program));
      interp.callByValue();
      fail("by-value " + name + " should throw EvalException");
    } catch (EvalException e) {
      // Expected
    }
  }

  private void nameThrowsCheck(String name, String program) {
    try {
      Interpreter interp = new Interpreter(new StringReader(program));
      interp.callByName();
      fail("by-name " + name + " should throw EvalException");
    } catch (EvalException e) {
      // Expected
    }
  }

  private void needThrowsCheck(String name, String program) {
    try {
      Interpreter interp = new Interpreter(new StringReader(program));
      interp.callByNeed();
      fail("by-need " + name + " should throw EvalException");
    } catch (EvalException e) {
      // Expected
    }
  }

  // ============ Constant Tests ============

  public void testIntegerConstant() {
    allCheck("intConstant", "42", "42");
    allCheck("negativeInt", "-100", "-100");
    allCheck("zero", "0", "0");
  }

  public void testBooleanConstant() {
    allCheck("boolTrue", "true", "true");
    allCheck("boolFalse", "false", "false");
  }

  public void testEmptyConstant() {
    allCheck("empty", "()", "empty");
  }

  // ============ Unary Operator Tests ============

  public void testUnaryPlus() {
    allCheck("unaryPlus", "42", "+ 42");
    allCheck("unaryPlusFive", "5", "+ 5");
  }

  public void testUnaryMinus() {
    allCheck("unaryMinus", "-42", "- 42");
    allCheck("unaryMinusNeg", "42", "- (- 42)");
  }

  public void testUnaryTilde() {
    allCheck("tildeFalse", "true", "~ false");
    allCheck("tildeTrue", "false", "~ true");
    allCheck("doubleNegate", "true", "~ (~ true)");
  }

  public void testUnaryOpTypeErrors() {
    valueThrowsCheck("unaryPlusOnBool", "+ true");
    valueThrowsCheck("unaryMinusOnBool", "- true");
    valueThrowsCheck("unaryTildeOnInt", "~ 42");
  }

  // ============ Binary Arithmetic Operator Tests ============

  public void testBinaryPlus() {
    allCheck("plus2and3", "5", "2 + 3");
    allCheck("plusWithNegative", "-1", "5 + (- 6)");
    allCheck("plusZero", "42", "42 + 0");
  }

  public void testBinaryMinus() {
    allCheck("minus5and3", "2", "5 - 3");
    allCheck("minusNegative", "11", "5 - (- 6)");
  }

  public void testBinaryTimes() {
    allCheck("times2and3", "6", "2 * 3");
    allCheck("timesZero", "0", "42 * 0");
    allCheck("timesNegative", "-6", "2 * (- 3)");
  }

  public void testBinaryDivide() {
    allCheck("divide6by2", "3", "6 / 2");
    allCheck("divideWithRemainder", "3", "7 / 2");
    allCheck("divideNegative", "-3", "(- 6) / 2");
  }

  public void testDivideByZero() {
    valueThrowsCheck("divideByZero", "5 / 0");
    nameThrowsCheck("divideByZeroName", "5 / 0");
    needThrowsCheck("divideByZeroNeed", "5 / 0");
  }

  public void testComplexArithmetic() {
    allCheck("orderOfOps", "18", "2 * 3 + 12");
    allCheck("nestedOps", "7", "(2 + 3) * (5 - 3) - 3");
  }

  // ============ Binary Comparison Operator Tests ============

  public void testLessThan() {
    allCheck("lt3and5", "true", "3 < 5");
    allCheck("lt5and3", "false", "5 < 3");
    allCheck("ltSame", "false", "5 < 5");
  }

  public void testGreaterThan() {
    allCheck("gt5and3", "true", "5 > 3");
    allCheck("gt3and5", "false", "3 > 5");
    allCheck("gtSame", "false", "5 > 5");
  }

  public void testLessThanEquals() {
    allCheck("lte3and5", "true", "3 <= 5");
    allCheck("lteSame", "true", "5 <= 5");
    allCheck("lte5and3", "false", "5 <= 3");
  }

  public void testGreaterThanEquals() {
    allCheck("gte5and3", "true", "5 >= 3");
    allCheck("gteSame", "true", "5 >= 5");
    allCheck("gte3and5", "false", "3 >= 5");
  }

  // ============ Equality Operator Tests ============

  public void testEqualsIntegers() {
    allCheck("eq5and5", "true", "5 = 5");
    allCheck("eq5and6", "false", "5 = 6");
  }

  public void testEqualsBooleans() {
    allCheck("eqTrueTrue", "true", "true = true");
    allCheck("eqFalseFalse", "true", "false = false");
    allCheck("eqTrueFalse", "false", "true = false");
  }

  public void testNotEquals() {
    allCheck("neq5and6", "true", "5 != 6");
    allCheck("neq5and5", "false", "5 != 5");
    allCheck("neqTrueFalse", "true", "true != false");
  }

  // ============ Short-Circuit Operator Tests ============

  public void testAndOperator() {
    allCheck("andTrueTrue", "true", "true & true");
    allCheck("andTrueFalse", "false", "true & false");
    allCheck("andFalseTrue", "false", "false & true");
    allCheck("andFalseFalse", "false", "false & false");
  }

  public void testAndShortCircuit() {
    // If the first operand is false, the second should not be evaluated
    // This should not throw an error even though 5 / 0 would normally throw
    nameCheck("andShortCircuitName", "false", "false & (5 / 0)");
    needCheck("andShortCircuitNeed", "false", "false & (5 / 0)");
  }

  public void testOrOperator() {
    allCheck("orTrueTrue", "true", "true | true");
    allCheck("orTrueFalse", "true", "true | false");
    allCheck("orFalseTrue", "true", "false | true");
    allCheck("orFalseFalse", "false", "false | false");
  }

  public void testOrShortCircuit() {
    // If the first operand is true, the second should not be evaluated
    nameCheck("orShortCircuitName", "true", "true | (5 / 0)");
    needCheck("orShortCircuitNeed", "true", "true | (5 / 0)");
  }

  public void testAndTypeError() {
    valueThrowsCheck("andNonBool", "5 & true");
    nameThrowsCheck("andNonBoolName", "5 & true");
  }

  // ============ If Expression Tests ============

  public void testIfThenElse() {
    allCheck("ifTrue", "10", "if true then 10 else 20");
    allCheck("ifFalse", "20", "if false then 10 else 20");
  }

  public void testIfWithExpressions() {
    allCheck("ifWithCompare", "5", "if 3 < 5 then 5 else 10");
    allCheck("ifNested", "15", "if true then (if false then 5 else 15) else 20");
  }

  public void testIfNonBooleanTest() {
    valueThrowsCheck("ifNonBool", "if 5 then 10 else 20");
    nameThrowsCheck("ifNonBoolName", "if 5 then 10 else 20");
  }

  public void testIfShortCircuitingBranches() {
    // The alternative should not be evaluated if test is true
    nameCheck("ifShortCircuitAlt", "5", "if true then 5 else (5 / 0)");
    needCheck("ifShortCircuitAltNeed", "5", "if true then 5 else (5 / 0)");
  }

  // ============ Primitive Function Tests ============

  public void testNumberPPrim() {
    allCheck("numberP5", "true", "number?(5)");
    allCheck("numberPTrue", "false", "number?(true)");
    allCheck("numberPEmpty", "false", "number?(empty)");
  }

  public void testFunctionPPrim() {
    allCheck("functionPNumberP", "true", "function?(number?)");
    allCheck("functionP5", "false", "function?(5)");
    allCheck("functionPMap", "true", "function?(map x to x)");
  }

  public void testListPPrim() {
    allCheck("listPEmpty", "true", "list?(empty)");
    allCheck("listPCons", "true", "list?(cons(1, empty))");
    allCheck("listP5", "false", "list?(5)");
  }

  public void testConsPPrim() {
    allCheck("consPEmpty", "false", "cons?(empty)");
    allCheck("consPSingle", "true", "cons?(cons(1, empty))");
    allCheck("cons5", "false", "cons?(5)");
  }

  public void testEmptyPPrim() {
    allCheck("emptyPEmpty", "true", "empty?(empty)");
    allCheck("emptyPCons", "false", "empty?(cons(1, empty))");
    allCheck("empty5", "false", "empty?(5)");
  }

  public void testArityPrim() {
    allCheck("arityNumberP", "1", "arity(number?)");
    allCheck("arityCons", "2", "arity(cons)");
    allCheck("arityMap", "1", "arity(map x to x)");
    allCheck("arityMapMulti", "3", "arity(map x,y,z to x)");
  }

  public void testArityNonFunction() {
    valueThrowsCheck("arityInt", "arity(5)");
    nameThrowsCheck("arityIntName", "arity(5)");
  }

  // ============ List Construction Tests ============

  public void testConsFunction() {
    allCheck("consSingle", "(1)", "cons(1, empty)");
    allCheck("consTwo", "(1 2)", "cons(1, cons(2, empty))");
    allCheck("consNested", "(1 (2 3))", "cons(1, cons(cons(2, cons(3, empty)), empty))");
  }

  public void testFirstFunction() {
    allCheck("firstSingle", "1", "first(cons(1, empty))");
    allCheck("firstMulti", "1", "first(cons(1, cons(2, empty)))");
  }

  public void testFirstNonCons() {
    valueThrowsCheck("firstEmpty", "first(empty)");
    valueThrowsCheck("firstInt", "first(5)");
  }

  public void testRestFunction() {
    allCheck("restSingle", "()", "rest(cons(1, empty))");
    allCheck("restMulti", "(2)", "rest(cons(1, cons(2, empty)))");
  }

  public void testRestNonCons() {
    valueThrowsCheck("restEmpty", "rest(empty)");
    valueThrowsCheck("restInt", "rest(5)");
  }

  // ============ Map (Lambda) Tests ============

  public void testSimpleMap() {
    allCheck("mapIdentity", "5", "(map x to x)(5)");
    allCheck("mapDouble", "10", "(map x to x + x)(5)");
  }

  public void testMapMultipleParams() {
    allCheck("mapAdd", "7", "(map x,y to x + y)(3, 4)");
    allCheck("mapMul", "12", "(map x,y to x * y)(3, 4)");
  }

  public void testMapArity() {
    allCheck("mapUnary", "1", "arity(map x to x)");
    allCheck("mapBinary", "2", "arity(map x,y to x + y)");
  }

  public void testMapWrongArity() {
    valueThrowsCheck("mapWrongArity", "(map x to x)(1, 2)");
    nameThrowsCheck("mapWrongArityName", "(map x to x)(1, 2)");
  }

  // ============ Let Expression Tests ============

  public void testLetSingleBinding() {
    allCheck("letSingle", "5", "let x := 5; in x");
  }

  public void testLetMultipleBindings() {
    allCheck("letMulti", "7", "let x := 3; y := 4; in x + y");
  }

  public void testLetWithExpression() {
    allCheck("letExpr", "25", "let x := 5; in x * x");
  }

  public void testLetScoping() {
    // Let bindings are parallel in Jam, like Scheme's let (not sequential like let*)
    allCheck("letScope", "15", "let x := 5; y := 10; in x + y");
  }

  // ============ Call-by-Value vs Call-by-Name/Need Tests ============

  public void testCallByValueEvaluatesAll() {
    // In call-by-value, all arguments are evaluated even if not used
    valueThrowsCheck("cbvEvalAll", "let f := map x,y to x; in f(5, 10 / 0)");
  }

  public void testCallByNameLazy() {
    // In call-by-name, arguments that are not used should not cause errors
    nameCheck("cbnDontEvalUnused", "5", "let f := map x,y to x; in f(5, 10 / 0)");
  }

  public void testCallByNeedLazy() {
    // In call-by-need, arguments that are not used should not cause errors
    needCheck("cbneedDontEvalUnused", "5", "let f := map x,y to x; in f(5, 10 / 0)");
  }

  public void testCallByValueEvaluatesMultipleTimes() {
    // In call-by-value, if an argument is used multiple times, it's only evaluated once
    allCheck("cbvUseMultipleTimes", "10", "let x := 5; in x + x");
  }

  public void testCallByNameReevaluates() {
    // In call-by-name, if an unevaluated argument is used multiple times, it's re-evaluated each time
    // Note: This is observable if we have side effects, which Jam doesn't have
    // Instead, we can test that both give the same observable result
    nameCheck("cbnUseMultipleTimes", "10", "let f := map x to x + x; in f(5)");
  }

  public void testCallByNeedCaches() {
    // In call-by-need, the first evaluation is cached
    // This is also observable only with side effects, but we can verify the result is correct
    needCheck("cbneedUseMultipleTimes", "10", "let f := map x to x + x; in f(5)");
  }

  public void testMapEquality() {
    // Two distinct map applications should create distinct closures
    allCheck("mapEquality1", "false", "(map x to x) = (map x to x)");
    // In call-by-value, the same closure should be equal to itself
    valueCheck("mapEquality2cbv", "true", "let m := map x to x; in m = m");
    // In call-by-name, each reference to m causes re-evaluation, creating new closures
    nameCheck("mapEquality2cbn", "false", "let m := map x to x; in m = m");
    // In call-by-need, the first evaluation is cached, so m = m
    needCheck("mapEquality2cbneed", "true", "let m := map x to x; in m = m");
  }

  // ============ Complex Expression Tests ============

  public void testNestedMaps() {
    allCheck("nestedMaps", "15", "((map x to (map y to x + y))(10))(5)");
  }

  public void testMapWithList() {
    allCheck("mapWithList", "(1 2 3)",
             "let append := map x,y to y; " +
             "    list1 := cons(1, cons(2, cons(3, empty))); " +
             "in append(empty, list1)");
  }

  public void testComplexControl() {
    allCheck("complexControl", "true",
             "let x := 5; y := 10; in if x < y then (x + y) = 15 else false");
  }

  public void testVariableInClosure() {
    allCheck("closureVar", "15",
             "let f := map x to map y to x + y; in (f(10))(5)");
  }

  public void testNestedLet() {
    allCheck("nestedLet", "15",
             "let x := 3; in let y := x + x; in x + y + y");
  }

  // ============ List Equality Tests ============

  public void testListEqualityStructural() {
    allCheck("listEqStructural1", "true",
             "cons(1, cons(2, empty)) = cons(1, cons(2, empty))");
    allCheck("listEqStructural2", "false",
             "cons(1, cons(2, empty)) = cons(1, cons(3, empty))");
  }

  public void testEmptyEquality() {
    allCheck("emptyEq", "true", "empty = empty");
  }
}

